import React, { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { Building2, Key, Route } from "lucide-react";
import { useTranslation } from "@/i18n";
import { type Profile } from "@/utils/branding-shared";
import { walletGetItem, walletSetItem } from "@/utils/storage";

export default function BuilderDetailsPage() {
  const { t } = useTranslation();
  const [builderName, setBuilderName] = useState<string>("");
  const [profile, setProfile] = useState<Profile | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    setBuilderName(walletGetItem("orderlyBuilderName") || "");
    const rawProfile = walletGetItem("orderlyProfile");
    if (rawProfile) {
      try {
        setProfile(JSON.parse(rawProfile) as Profile);
      } catch {}
    }
  }, []);

  function validate(value: string): string | null {
    if (value.trim().length > 0 && value.trim().length < 3) {
      return "Builder name must be at least 3 characters";
    }
    if (value.trim().length > 30) {
      return "Builder name must be at most 30 characters";
    }
    return null;
  }

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    const value = e.target.value;
    setBuilderName(value);
    setError(validate(value));
  }

  function handleSave() {
    const validationError = validate(builderName);
    if (validationError) {
      setError(validationError);
      return;
    }
    walletSetItem("orderlyBuilderName", builderName.trim());
    showToast(t("builderDetails.saved"));
  }

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  const pathwayDisplay =
    profile?.pathway === "low-code"
      ? "No-code"
      : profile?.pathway === "sdk"
        ? "SDK/API"
        : profile?.pathway || "—";

  return (
    <PageShell pageTitle="Builder Details">
      <div className="space-y-5">
        <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="mb-5 flex items-center gap-2">
            <div className="flex h-8 w-8 items-center justify-center rounded-md bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
              <Building2 className="h-4 w-4" />
            </div>
          </div>

          <div className="mb-5">
            <label className="mb-1.5 block text-sm text-(--fg-secondary)">
              Builder name
            </label>
            <input
              type="text"
              value={builderName}
              onChange={handleChange}
              placeholder="Enter builder name"
              minLength={3}
              maxLength={30}
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
            />
            {error ? (
              <p className="mt-1.5 text-xs text-[#FF6390]">{error}</p>
            ) : (
              <p className="mt-1.5 text-xs text-(--fg-secondary)">
                Min 3 characters, max 30 characters
              </p>
            )}
          </div>

          <button
            type="button"
            onClick={handleSave}
            disabled={!!error || builderName.trim().length < 3}
            className="inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
            style={{ background: "var(--bg-brand-grad)" }}
          >
            Save builder name
          </button>
        </div>

        <div className="grid grid-cols-1 gap-5 sm:grid-cols-2">
          <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5">
            <div className="mb-3 flex items-center gap-2 text-sm text-(--fg-secondary)">
              <div className="flex h-6 w-6 items-center justify-center rounded-md bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                <Key className="h-4 w-4" />
              </div>
              Distributor Code
            </div>
            <div className="text-xl font-medium text-(--fg-primary)">
              {profile?.distributorCode || "—"}
            </div>
          </div>

          <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5">
            <div className="mb-3 flex items-center gap-2 text-sm text-(--fg-secondary)">
              <div className="flex h-6 w-6 items-center justify-center rounded-md bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                <Route className="h-4 w-4" />
              </div>
              Pathway
            </div>
            <div className="text-xl font-medium text-(--fg-primary)">
              {pathwayDisplay}
            </div>
          </div>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
